mapper.select:
SELECT
`id`, `source`, `frame`, `customer`, `time`, `number`, `total`, `actual`, `money`, `cost`,
`account`, `people`, `logistics`, `file`, `data`, `more`, `examine`, `nucleus`, `cse`,
`invoice`, `check`, `user`
FROM `sell`


        AND EXISTS (
        SELECT 1 FROM sell_info sfi
        WHERE sfi.pid = sell.id AND sfi.goods LIKE CONCAT('%', #{query.goodsName}, '%')
        )


        AND number LIKE CONCAT('%', #{query.number}, '%')


        AND customer LIKE CONCAT('%', #{query.customer}, '%')


        AND people LIKE CONCAT('%', #{query.people}, '%')


        AND user LIKE CONCAT('%', #{query.user}, '%')


        AND time >= #{query.startTime}


        AND time <= #{query.endTime}


        AND examine = #{query.examine}


        AND nucleus = #{query.nucleus}


        AND cse = #{query.cse}


        AND invoice = #{query.invoice}


        AND check = #{query.check}


        AND data LIKE CONCAT('%', #{query.data}, '%')


ORDER BY time DESC
